cd "/c/Dev/dev_safetyreport/workspace/portal" && python3 << 'EOF'
import json
import sys

sys.stdout.reconfigure(encoding='utf-8')

with open('.understand-anything/knowledge-graph.json', 'r', encoding='utf-8') as f:
    data = json.load(f)

# AutoClsfServiceImpl 관련 함수 상세 정보
print("=" * 90)
print("1. AutoClsfServiceImpl 클래스 상세 정보")
print("=" * 90)

auto_clsf_service = None
auto_clsf_functions = []

if 'nodes' in data:
    for node in data['nodes']:
        if 'AutoClsfServiceImpl.java' in node.get('id', ''):
            if node.get('type') == 'class':
                auto_clsf_service = node
            elif node.get('type') == 'function':
                auto_clsf_functions.append(node)

if auto_clsf_service:
    print(f"\n클래스명: {auto_clsf_service.get('name')}")
    print(f"파일: {auto_clsf_service.get('filePath')}")
    print(f"\n설명: {auto_clsf_service.get('summary')}")
    print(f"태그: {', '.join(auto_clsf_service.get('tags', []))}")

print(f"\n포함된 함수 ({len(auto_clsf_functions)}개):")
for func in auto_clsf_functions:
    print(f"\n  - {func.get('name')}")
    print(f"    요약: {func.get('summary', 'N/A')[:80]}")
    if func.get('tags'):
        print(f"    태그: {', '.join(func.get('tags', []))}")

# 신고유형 관련 DTO/Entity
print("\n" + "=" * 90)
print("2. 신고유형(ReportType) 관련 데이터 모델")
print("=" * 90)

report_type_nodes = []
if 'nodes' in data:
    for node in data['nodes']:
        name = node.get('name', '')
        if any(kw in name for kw in ['ReportType', 'SafeReport', 'DisasterType', 'SafeType', 'CodeInfo']):
            if node.get('type') in ['class', 'file', 'interface']:
                report_type_nodes.append(node)

for i, node in enumerate(report_type_nodes[:20]):
    print(f"\n[{i+1}] {node.get('name')}")
    print(f"    타입: {node.get('type')}")
    print(f"    설명: {node.get('summary', 'N/A')[:100]}")
    if node.get('tags'):
        print(f"    태그: {', '.join(node.get('tags', []))}")

# 자동분류 로직과 관련된 핵심 클래스들
print("\n" + "=" * 90)
print("3. 자동분류 관련 핵심 클래스/인터페이스")
print("=" * 90)

core_classes = []
if 'nodes' in data:
    for node in data['nodes']:
        if node.get('type') in ['class', 'interface']:
            name = node.get('name', '')
            if any(kw in name for kw in ['AutoClsf', 'SafeReport', 'CodeInfo', 'Mapper']):
                if 'Test' not in name:  # 테스트 제외
                    core_classes.append(node)

print(f"\n총 {len(core_classes)}개의 핵심 클래스/인터페이스 발견\n")

# 분류: AutoClsf 관련
print("AutoClsf 관련:")
for node in core_classes:
    if 'AutoClsf' in node.get('name', ''):
        print(f"  - {node.get('name'):<40} ({node.get('type')})")

print("\nSafeReport 관련:")
for node in core_classes:
    if 'SafeReport' in node.get('name', '') and 'AutoClsf' not in node.get('name', ''):
        print(f"  - {node.get('name'):<40} ({node.get('type')})")

print("\nCodeInfo 관련:")
for node in core_classes:
    if 'CodeInfo' in node.get('name', ''):
        print(f"  - {node.get('name'):<40} ({node.get('type')})")

EOF
